<?php
namespace App\Models;use Illuminate\Database\Eloquent\Model;class Hunt extends Model{protected $guarded=[];protected $casts=['enemy_count'=>'integer','rounds_count'=>'integer','character_health_before'=>'integer','character_health_after'=>'integer','started_at'=>'datetime','completed_at'=>'datetime'];public function character(){return$this->belongsTo(Character::class);}public function zone(){return$this->belongsTo(Zone::class);}public function enemies(){return$this->hasMany(HuntEnemy::class)->orderBy('position');}}
